mapper.select:
SELECT COUNT(*)
FROM FWK_COMPONENT
WHERE COMPONENT_ID = #{componentId}

SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT TRIM(c.COMPONENT_ID) AS componentId, TRIM(c.COMPONENT_NAME) AS componentName, c.COMPONENT_DESC AS componentDesc, c.COMPONENT_TYPE AS componentType, TRIM(c.COMPONENT_CLASS_NAME) AS componentClassName, TRIM(c.COMPONENT_METHOD_NAME) AS componentMethodName, c.COMPONENT_CREATE_TYPE AS componentCreateType, c.BIZ_GROUP_ID AS bizGroupId, c.USE_YN AS useYn, c.LAST_UPDATE_DTIME AS lastUpdateDtime, TRIM(c.LAST_UPDATE_USER_ID) AS lastUpdateUserId FROM FWK_COMPONENT c
ORDER BY
c.COMPONENT_NAME c.COMPONENT_TYPE c.USE_YN c.LAST_UPDATE_DTIME c.COMPONENT_ID
DESC ASC
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}

