INSERT INTO FWK_COMPONENT_PARAM (COMPONENT_ID, PARAM_SEQ_NO, PARAM_KEY, PARAM_DESC, DEFAULT_PARAM_VALUE) SELECT A.* FROM (
SELECT #{componentId}, #{item.paramSeqNo}, #{item.paramKey}, #{item.paramDesc, jdbcType=VARCHAR}, #{item.defaultParamValue, jdbcType=VARCHAR} FROM DUAL
) A
